#include <stdio.h>
#include <stdlib.h>
int main() {
    int *data = NULL;
    size_t cap = 0, sz = 0;
    int val;
    // Read all integers until EOF
    while (scanf("%d", &val) == 1) {
        if (sz == cap) {
            cap = cap ? cap * 2 : 16;
            data = realloc(data, cap * sizeof(int));
        }
        data[sz++] = val;
    }
    for (size_t i = 0; i + 2 < sz; i += 3) {
        int front = data[i];
        int rear = data[i + 1];
        int maxSize = data[i + 2];
        int empty = (front == -1 && rear == -1);
        int curSize;
        if (empty) {
            curSize = 0;
        } else if (rear >= front) {
            curSize = rear - front + 1;
        } else {
            curSize = maxSize - front + rear + 1;
        }
        int full = (curSize == maxSize);
        printf("%s\n", empty ? "Queue is Empty" : "Queue is Not Empty");
        printf("%s\n", full ? "Queue is Full" : "Queue is Not Full");
        printf("Current Size: %d", curSize);
        if (i + 3 < sz) printf("\n");
    }
    free(data);
    return 0;
}

