import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        List<Long> list = new ArrayList<>();
        String line;
        while ((line = br.readLine()) != null) {
            line = line.trim();
            if (line.isEmpty()) continue;
            StringTokenizer st = new StringTokenizer(line);
            while (st.hasMoreTokens()) {
                list.add(Long.parseLong(st.nextToken()));
            }
        }
        for (int i = 0; i + 2 < list.size(); i += 3) {
            long front = list.get(i);
            long rear = list.get(i + 1);
            long maxSize = list.get(i + 2);
            boolean empty = (front == -1 && rear == -1);
            long curSize;
            if (empty) curSize = 0;
            else if (rear >= front) curSize = rear - front + 1;
            else curSize = maxSize - front + rear + 1;
            boolean full = (curSize == maxSize);
            sb.append(empty ? "Queue is Empty" : "Queue is Not Empty").append('\n');
            sb.append(full ? "Queue is Full" : "Queue is Not Full").append('\n');
            sb.append("Current Size: ").append(curSize);
            if (i + 3 < list.size()) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

